--
-- Disparadores `pedidos`
--
DELIMITER $$
CREATE TRIGGER `trg_pedidos_timestamp` BEFORE INSERT ON `pedidos` FOR EACH ROW BEGIN
    -- Si no envían la fecha, o envían 0, la calculamos ahora mismo
    IF NEW.fecha_creacion = 0 OR NEW.fecha_creacion IS NULL THEN
        SET NEW.fecha_creacion = DATE_FORMAT(NOW(), '%Y%m%d'); -- Ej: 20260115
    END IF;

    -- Si no envían la hora, la calculamos ahora mismo
    IF NEW.hora_creacion = '00:00' OR NEW.hora_creacion IS NULL THEN
        SET NEW.hora_creacion = DATE_FORMAT(NOW(), '%H:%i');   -- Ej: 16:31
    END IF;
END
$$
DELIMITER ;

