--
-- Estructura de tabla para la tabla `pedidos_detalle`
--

CREATE TABLE `pedidos_detalle` (
  `id` int(11) NOT NULL,
  `pedido_id` int(11) NOT NULL,
  `producto_id` int(11) NOT NULL,
  `cod_producto` varchar(50) DEFAULT NULL,
  `unidad_medida` varchar(10) DEFAULT NULL,
  `cantidad` int(11) NOT NULL,
  `precio_neto` int(11) NOT NULL,
  `precio_bruto` int(11) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

--
-- Volcado de datos para la tabla `pedidos_detalle`
--


--
-- Disparadores `pedidos_detalle`
--
DELIMITER $$
CREATE TRIGGER `trg_actualizar_pedido_delete` AFTER DELETE ON `pedidos_detalle` FOR EACH ROW BEGIN
    UPDATE pedidos SET 
        cantidad_items = (SELECT COUNT(*) FROM pedidos_detalle WHERE pedido_id = OLD.pedido_id),
        cantidad_total_productos = (SELECT IFNULL(SUM(cantidad), 0) FROM pedidos_detalle WHERE pedido_id = OLD.pedido_id),
        monto_total = (SELECT IFNULL(SUM(precio_bruto * cantidad), 0) FROM pedidos_detalle WHERE pedido_id = OLD.pedido_id) + IFNULL(costo_envio, 0)
    WHERE id = OLD.pedido_id;
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_actualizar_pedido_insert` AFTER INSERT ON `pedidos_detalle` FOR EACH ROW BEGIN
    UPDATE pedidos SET 
        -- Cuenta cuántas filas hay (tipos de productos)
        cantidad_items = (SELECT COUNT(*) FROM pedidos_detalle WHERE pedido_id = NEW.pedido_id),
        
        -- Suma todas las cantidades unitarias
        cantidad_total_productos = (SELECT IFNULL(SUM(cantidad), 0) FROM pedidos_detalle WHERE pedido_id = NEW.pedido_id),
        
        -- (Bonus) Recalcula el precio total sumando productos + costo de envío actual
        monto_total = (SELECT IFNULL(SUM(precio_bruto * cantidad), 0) FROM pedidos_detalle WHERE pedido_id = NEW.pedido_id) + IFNULL(costo_envio, 0)
    WHERE id = NEW.pedido_id;
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `trg_actualizar_pedido_update` AFTER UPDATE ON `pedidos_detalle` FOR EACH ROW BEGIN
    UPDATE pedidos SET 
        cantidad_items = (SELECT COUNT(*) FROM pedidos_detalle WHERE pedido_id = NEW.pedido_id),
        cantidad_total_productos = (SELECT IFNULL(SUM(cantidad), 0) FROM pedidos_detalle WHERE pedido_id = NEW.pedido_id),
        monto_total = (SELECT IFNULL(SUM(precio_bruto * cantidad), 0) FROM pedidos_detalle WHERE pedido_id = NEW.pedido_id) + IFNULL(costo_envio, 0)
    WHERE id = NEW.pedido_id;
END
$$
DELIMITER ;

